import{_ as e,o as r,c as t,a2 as n}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"프론트 전에 — enabler 먼저, 그리고 \\"보류\\"였던 springdoc이 Boot4에서 됐다","description":"","frontmatter":{"slug":"frontend-enablers-springdoc","title":"프론트 전에 — enabler 먼저, 그리고 \\"보류\\"였던 springdoc이 Boot4에서 됐다","authors":[],"tags":["spec-kit","sdd","spring-boot","cors","openapi","springdoc","frontend"],"created":"2026-05-31 16:10 (KST)","date":"2026-05-31T07:10:00.000Z"},"headers":[],"relativePath":"journal/2026-05-31-frontend-enablers-springdoc.md","filePath":"journal/2026-05-31-frontend-enablers-springdoc.md","lastUpdated":1781092690000}'),a={name:"journal/2026-05-31-frontend-enablers-springdoc.md"};function s(d,o,i,c,p,l){return r(),t("div",null,[...o[0]||(o[0]=[n('<p>feature 004 를 마감하고 &quot;이제 다 끝났나?&quot;를 점검하다 보니, 정작 <strong>프론트엔드가 없다</strong>는 사실이 드러났다. 004 는 22개 REST API + 데모 페이지 한 장이 전부였다. 프론트로 넘어가기 전에 무엇을 먼저 해야 하는지 정리했고, 그 과정에서 004 가 <strong>보류</strong>했던 springdoc 이 Spring Boot 4 에서 의외로 <strong>동작</strong>한다는 걸 확인했다.</p><h2 id="프론트-전에-뭘-해야-하나" tabindex="-1">&quot;프론트 전에 뭘 해야 하나&quot; <a class="header-anchor" href="#프론트-전에-뭘-해야-하나" aria-label="Permalink to &quot;&quot;프론트 전에 뭘 해야 하나&quot;&quot;">​</a></h2><p>프론트 스택은 <strong>Vue 3 + Vite, 별도 dev server + 프록시</strong>로 정했다(이전 소스 <code>C:/ax/lego</code> 가 Vue3/Vuetify/Pinia 였고, <code>C:/ax/vugrid</code> 가 Vue 래퍼를 주니 자연스러운 선택). 그런데 별도 dev server 는 <strong>다른 출처(origin)</strong> 라, 백엔드에 CORS 설정이 없으면 API 호출이 전부 막힌다. 그래서 프론트 본체 전에 <strong>enabler 두 가지</strong>를 먼저 닫기로 했다:</p><ol><li><strong>CORS</strong> — 프론트 dev server(<code>localhost:5173</code>)가 <code>/api/v1/**</code> 를 부를 수 있게.</li><li><strong>OpenAPI 문서</strong> — 타입 안전 API 클라이언트 생성·탐색용.</li></ol><p>나머지 백엔드 잔여(SQL 이력·메뉴 세분 권한·실 SMTP)는 프론트를 막지 않으니 뒤로 미뤘다. 이 묶음을 feature 005(플랫폼 운영 완성)로 스펙했다.</p><h2 id="cors-—-차단요인이지만-5분" tabindex="-1">CORS — 차단요인이지만 5분 <a class="header-anchor" href="#cors-—-차단요인이지만-5분" aria-label="Permalink to &quot;CORS — 차단요인이지만 5분&quot;">​</a></h2><p><code>SecurityConfig</code> 에 <code>CorsConfigurationSource</code> 빈을 더하고 <code>.cors(withDefaults())</code> 한 줄. 허용 출처는 <code>platform.cors.allowed-origins</code> 로 외부화(기본 <code>localhost:5173</code>), 자격증명 허용 때문에 와일드카드 출처는 안 쓴다. 운영처럼 <strong>동일 출처로 배포하면 프리플라이트가 없어 영향이 0</strong> 이다. 허용/미허용 출처 프리플라이트를 테스트로 못박았다.</p><h2 id="springdoc-—-보류-는-가설일-뿐이었다" tabindex="-1">springdoc — &quot;보류&quot;는 가설일 뿐이었다 <a class="header-anchor" href="#springdoc-—-보류-는-가설일-뿐이었다" aria-label="Permalink to &quot;springdoc — &quot;보류&quot;는 가설일 뿐이었다&quot;">​</a></h2><p>여기가 이번의 배움이다. 004 의 plan 은 springdoc 을 <strong>범위 밖</strong>으로 두며 이렇게 적었다:</p><blockquote><p>springdoc-openapi: Spring Boot 4(Spring Framework 7) 호환 확정 전까지 범위 밖으로 보류.</p></blockquote><p>합리적인 보수였다 — springdoc 은 Spring MVC 내부에 깊게 손을 대서, Spring 메이저 업글에 잘 깨진다. 그런데 보류는 <strong>검증되지 않은 가설</strong>이기도 하다. 그래서 스파이크를 했다:</p><ul><li>lego 가 쓰던 <code>springdoc-openapi-starter-webmvc-ui:2.8.6</code> 을 그대로 추가.</li><li>가장 싼 게이트부터: <strong>컨텍스트가 뜨는가?</strong> → 단일 부팅 테스트. 떴다.</li><li>적재 ≠ 동작이다. <strong><code>/v3/api-docs</code> 가 실제로 스펙을 만들어 주는가?</strong> → 응답에 <code>/api/v1/auth/login</code>·<code>/api/v1/approvals</code> 가 들어있는지 본다. 들어있었다.</li></ul><p>즉 2.8.6 이 Boot4 에서 <strong>그냥 됐다</strong>. 004 의 보류 사유가 해소된 것이다. 005 스펙의 해당 가정과 Open Question 을 &quot;확인됨&quot;으로 바꿨다.</p><p>교훈: <strong>&quot;호환 안 될 것 같다&quot;는 보류는 스파이크 한 번이면 사실로 바뀐다.</strong> 비용도 작다 — 의존성 한 줄 + 부팅 테스트 1개 + 런타임 동작 테스트 1개. 게이트를 &quot;적재 → 실동작&quot; 두 단계로 나눠서, 싸게 빨리 틀리거나 맞도록 했다.</p><h2 id="지금-상태" tabindex="-1">지금 상태 <a class="header-anchor" href="#지금-상태" aria-label="Permalink to &quot;지금 상태&quot;">​</a></h2><p>enabler 2종 모두 초록(전체 <code>gradle :app:test</code> 28/28). 프론트는 이제 <strong>CORS 로 dev server 호출 + OpenAPI 로 클라이언트 생성</strong>이 가능한 토대 위에서 시작할 수 있다. 다음은 프론트 본체(feature 006) — 화면 범위부터 정의하는 brainstorming → spec 순으로 간다.</p>',16)])])}const h=e(a,[["render",s]]);export{u as __pageData,h as default};
